class Solution:
    def smallestString(self, s: str) -> str:
        n = len(s)
        a0 = ord('a')

        # We must apply exactly once: choose l..r, and for i in [l,r]:
        # c -> prev(c) with wrap: 'a' -> 'z'
        # Goal: lexicographically smallest resulting string.

        arr = list(s)

        def prev_char(ch: str) -> str:
            if ch == 'a':
                return 'z'
            return chr(ord(ch) - 1)

        # Find leftmost index where we can make the string strictly smaller:
        # - If s[i] != 'a', changing it to prev makes it smaller.
        # - If s[i] == 'a', changing it makes it larger ('z'), so never helps
        #   for lexicographic decrease at the first differing position.
        l = -1
        for i, ch in enumerate(arr):
            if ch != 'a':
                l = i
                break

        if l == -1:
            # All characters are 'a'. Any operation makes some position become 'z' (larger).
            # To get lexicographically smallest, we want the first position affected as far right as possible.
            # That means choose the smallest possible prefix impact: l = n-1, r = n-1.
            arr[-1] = 'z'
            return ''.join(arr)

        # Choose the earliest improving position l. Now decide how far to extend.
        # Extending past points where s[i] == 'a' would wrap to 'z' (larger),
        # and that would create an earlier worsening (at the first such index), making the string worse.
        r = l
        for j in range(l, n):
            if arr[j] == 'a':
                break
            r = j

        # Apply operation to l..r
        for i in range(l, r + 1):
            arr[i] = prev_char(arr[i])

        return ''.join(arr)
